SELECT id, connection_id AS connectionId, table_name AS tableName, column_name AS columnName, chunk_text AS chunkText, embedding::text AS embedding, status, remark, create_by AS createBy, create_time AS createTime, update_by AS updateBy, update_time AS updateTime, 1 - (embedding <=> #{embedding}::vector) AS similarity FROM text2sql_column_embedding WHERE connection_id = #{connectionId} AND status = 1 AND table_name IN
#{t}
ORDER BY embedding <=> #{embedding}::vector LIMIT #{limit}
